const fs = require('fs');

const HEARTBEAT_PATH = '/vault/.pensieve/heartbeat.txt';
const THRESHOLD_MINUTES = 120;

if (!fs.existsSync(HEARTBEAT_PATH)) {
  throw new Error(`pensieve 心跳檔不存在（${HEARTBEAT_PATH}），pensieve 可能尚未啟動`);
}

const lastHeartbeat = fs.readFileSync(HEARTBEAT_PATH, 'utf-8').trim();
const ageMinutes = (Date.now() - new Date(lastHeartbeat).getTime()) / 60000;

if (ageMinutes > THRESHOLD_MINUTES) {
  throw new Error(`pensieve 心跳逾時：最後心跳 ${lastHeartbeat}（距今約 ${Math.round(ageMinutes)} 分鐘，閾值 ${THRESHOLD_MINUTES} 分鐘）`);
}

return [{ json: { lastHeartbeat, ageMinutes } }];
